import { Component } from '@angular/core';
import { AppService, Toast } from './services/app.service';
import { Observable } from 'rxjs';

@Component({
  selector: 'app-root',
  templateUrl: './app.component.html',
  styleUrls: ['./app.component.css']
})
export class AppComponent {
  toasts$: Observable<Toast[]>;

  constructor(private appService: AppService) {
    this.toasts$ = this.appService.toasts$;
  }

  removeToast(toast: Toast): void {
    this.appService.removeToast(toast.id);
  }

  getToastClass(toast: Toast): string {
    return `toast-${toast.type}`;
  }

  getToastIcon(toast: Toast): string {
    switch (toast.type) {
      case 'success':
        return '✅';
      case 'error':
        return '❌';
      case 'warning':
        return '⚠️';
      case 'info':
      default:
        return 'ℹ️';
    }
  }
}
<app-nav></app-nav>
<router-outlet></router-outlet>

<div class="toast-container">
  <div
    *ngFor="let toast of toasts$ | async"
    class="toast"
    [ngClass]="getToastClass(toast)"
    (click)="removeToast(toast)"
  >
    <span style="margin-right: 8px;">{{ getToastIcon(toast) }}</span>
    {{ toast.message }}
  </div>
</div>
